import{_ as e,a,b as o,c as n,d as r}from"./chunks/复制刷新令牌.IwW3dosg.js";import{_ as i,o as d,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"OneDrive Channel சேர்க்கவும்","description":"","frontmatter":{},"headers":[],"relativePath":"ta/upload/onedrive.md","filePath":"ta/upload/onedrive.md","lastUpdated":1781962217000}'),c={name:"ta/upload/onedrive.md"};function p(h,t,u,m,f,b){return d(),s("div",null,[...t[0]||(t[0]=[l('<h1 id="onedrive-channel-சேர்க்கவும்" tabindex="-1">OneDrive Channel சேர்க்கவும் <a class="header-anchor" href="#onedrive-channel-சேர்க்கவும்" aria-label="Permalink to &quot;OneDrive Channel சேர்க்கவும்&quot;">​</a></h1><h2 id="தொடங்குவதற்கு-முன்-தேவையானவை" tabindex="-1">தொடங்குவதற்கு முன் தேவையானவை <a class="header-anchor" href="#தொடங்குவதற்கு-முன்-தேவையானவை" aria-label="Permalink to &quot;தொடங்குவதற்கு முன் தேவையானவை&quot;">​</a></h2><table tabindex="0"><thead><tr><th>தேவை</th><th>ஏன் தேவை</th></tr></thead><tbody><tr><td>Microsoft account</td><td>Microsoft admin pages அணுகவும் OneDrive authorize செய்யவும்</td></tr><tr><td>உங்கள் ImgBed domain</td><td>OAuth callback URL-க்கு</td></tr><tr><td>App registration</td><td><code>Client ID</code> மற்றும் <code>Client Secret</code> உருவாக்க</td></tr><tr><td>OneDrive account</td><td>உண்மையான file storage location ஆக</td></tr></tbody></table><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><h3 id="step-1-microsoft-entra-id-திறக்கவும்" tabindex="-1">Step 1: Microsoft Entra ID திறக்கவும் <a class="header-anchor" href="#step-1-microsoft-entra-id-திறக்கவும்" aria-label="Permalink to &quot;Step 1: Microsoft Entra ID திறக்கவும்&quot;">​</a></h3><ol><li><code>portal.azure.com</code> திறக்கவும்.</li><li>மேலே search-ல் <code>Microsoft Entra ID</code> தேடவும்.</li><li>target page dropdown-ல் தெரியவில்லை என்றால்:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Continue searching in Microsoft Entra ID</span></span></code></pre></div><ol start="4"><li><code>Microsoft Entra ID</code> திறக்கவும்.</li><li><code>App registrations</code> திறக்கவும்.</li><li><code>New registration</code> கிளிக் செய்யவும்.</li></ol><h3 id="step-2-app-register-செய்யவும்" tabindex="-1">Step 2: App Register செய்யவும் <a class="header-anchor" href="#step-2-app-register-செய்யவும்" aria-label="Permalink to &quot;Step 2: App Register செய்யவும்&quot;">​</a></h3><p><code>New registration</code> page-ல்:</p><table tabindex="0"><thead><tr><th>Field</th><th>What To Enter</th></tr></thead><tbody><tr><td>Name</td><td>அறியக்கூடிய பெயர், உதா. <code>imgbed-onedrive</code></td></tr><tr><td>Supported account types</td><td>கீழே உள்ள table படி தேர்வு செய்யவும்</td></tr><tr><td>Redirect URI type</td><td><code>Web</code></td></tr><tr><td>Redirect URI</td><td><code>https://your-domain.com/api/oauth/onedrive/callback</code></td></tr></tbody></table><p>Account type வழிகாட்டி:</p><table tabindex="0"><thead><tr><th>உங்கள் Scenario</th><th>Supported Account Types</th></tr></thead><tbody><tr><td>Personal OneDrive மட்டும்</td><td>personal Microsoft account option தேர்வு செய்யவும்.</td></tr><tr><td>personal மற்றும் work/school accounts இரண்டும்</td><td>இரண்டையும் support செய்யும் option தேர்வு செய்யவும்.</td></tr><tr><td>Company அல்லது school OneDrive மட்டும்</td><td>organizational account option தேர்வு செய்யவும்.</td></tr></tbody></table><p>form நிரப்பிய பிறகு register கிளிக் செய்யவும்.</p><p><img src="'+e+'" alt="Create OneDrive app" loading="lazy"></p><h3 id="step-3-app-information-copy-செய்யவும்" tabindex="-1">Step 3: App Information Copy செய்யவும் <a class="header-anchor" href="#step-3-app-information-copy-செய்யவும்" aria-label="Permalink to &quot;Step 3: App Information Copy செய்யவும்&quot;">​</a></h3><p>app உருவான பிறகு overview page-ல் இருந்து:</p><table tabindex="0"><thead><tr><th>Microsoft Field</th><th>ImgBed Field</th></tr></thead><tbody><tr><td><code>Application (client) ID</code></td><td><code>Client ID</code></td></tr><tr><td><code>Directory (tenant) ID</code></td><td>organizational accounts-க்கு <code>Tenant ID</code></td></tr></tbody></table><p><img src="'+a+'" alt="Application and tenant IDs" loading="lazy"></p><h3 id="step-4-client-secret-உருவாக்கவும்" tabindex="-1">Step 4: Client Secret உருவாக்கவும் <a class="header-anchor" href="#step-4-client-secret-உருவாக்கவும்" aria-label="Permalink to &quot;Step 4: Client Secret உருவாக்கவும்&quot;">​</a></h3><ol><li><code>Certificates &amp; secrets</code> திறக்கவும்.</li><li><code>New client secret</code> கிளிக் செய்யவும்.</li><li>description உள்ளிடவும்.</li><li>expiration period தேர்வு செய்யவும்.</li><li>உருவானதும் <code>Value</code> உடனே copy செய்யவும்.</li></ol><p><img src="'+o+'" alt="Save client secret value" loading="lazy"></p><h3 id="step-5-api-permissions-சேர்க்கவும்" tabindex="-1">Step 5: API Permissions சேர்க்கவும் <a class="header-anchor" href="#step-5-api-permissions-சேர்க்கவும்" aria-label="Permalink to &quot;Step 5: API Permissions சேர்க்கவும்&quot;">​</a></h3><ol><li><code>API permissions</code> திறக்கவும்.</li><li><code>Add a permission</code> கிளிக் செய்யவும்.</li><li><code>Microsoft Graph</code> தேர்வு செய்யவும்.</li><li><code>Delegated permissions</code> தேர்வு செய்யவும்.</li><li>இந்த permissions சேர்க்கவும்:</li></ol><table tabindex="0"><thead><tr><th>Permission</th><th>Purpose</th></tr></thead><tbody><tr><td><code>Files.ReadWrite.All</code></td><td>files upload, folders create, files delete செய்ய</td></tr><tr><td><code>offline_access</code></td><td>ImgBed <code>Refresh Token</code> பெற அனுமதி</td></tr><tr><td><code>User.Read</code></td><td>account மற்றும் quota information படிக்க</td></tr></tbody></table><h3 id="step-6-imgbed-ல்-onedrive-channel-நிரப்பவும்" tabindex="-1">Step 6: ImgBed-ல் OneDrive Channel நிரப்பவும் <a class="header-anchor" href="#step-6-imgbed-ல்-onedrive-channel-நிரப்பவும்" aria-label="Permalink to &quot;Step 6: ImgBed-ல் OneDrive Channel நிரப்பவும்&quot;">​</a></h3><p>Upload Settings-ல் <code>OneDrive</code> தேர்வு செய்து:</p><table tabindex="0"><thead><tr><th>ImgBed Field</th><th>What To Enter</th></tr></thead><tbody><tr><td>Channel name</td><td>அறியக்கூடிய பெயர், உதா. <code>Main OneDrive</code></td></tr><tr><td>Client ID</td><td>Microsoft <code>Application (client) ID</code></td></tr><tr><td>Client Secret</td><td>copy செய்த <code>Client Secret Value</code></td></tr><tr><td>Tenant ID</td><td>கீழே உள்ள table படி</td></tr><tr><td>Refresh Token</td><td>இப்போது காலியாக விடவும்</td></tr><tr><td>Root directory</td><td>Optional. default <code>imgbed</code>.</td></tr><tr><td>Note</td><td>Optional</td></tr></tbody></table><p><img src="'+n+'" alt="Fill OneDrive channel config" loading="lazy"></p><p><code>Tenant ID</code> நிரப்புவது:</p><table tabindex="0"><thead><tr><th>நீங்கள் தேர்வு செய்த Account Type</th><th>ImgBed <code>Tenant ID</code></th></tr></thead><tbody><tr><td>Personal accounts</td><td><code>consumers</code></td></tr><tr><td>Personal + organizational accounts</td><td><code>common</code></td></tr><tr><td>Current organization only</td><td><code>Directory (tenant) ID</code></td></tr></tbody></table><h3 id="step-7-refresh-token-பெறவும்" tabindex="-1">Step 7: Refresh Token பெறவும் <a class="header-anchor" href="#step-7-refresh-token-பெறவும்" aria-label="Permalink to &quot;Step 7: Refresh Token பெறவும்&quot;">​</a></h3><ol><li>ImgBed-ல் <code>Get Token</code> கிளிக் செய்யவும்.</li><li>connect செய்ய வேண்டிய Microsoft account-ல் sign in செய்யவும்.</li><li>authorization prompt approve செய்யவும்.</li><li>callback page <code>Refresh Token</code> காட்டும்.</li><li>அதை copy செய்யவும்.</li><li>ImgBed-க்கு திரும்பி <code>Refresh Token</code> field-ல் paste செய்யவும்.</li></ol><p><img src="'+r+`" alt="Copy refresh token" loading="lazy"></p><h3 id="step-8-channel-save-செய்யவும்" tabindex="-1">Step 8: Channel Save செய்யவும் <a class="header-anchor" href="#step-8-channel-save-செய்யவும்" aria-label="Permalink to &quot;Step 8: Channel Save செய்யவும்&quot;">​</a></h3><p>அனைத்து fields நிரப்பிய பிறகு channel save செய்யவும்.</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>portal.azure.com திறக்கவும்</span></span>
<span class="line"><span>-&gt; Microsoft Entra ID தேடவும்</span></span>
<span class="line"><span>-&gt; App registrations திறக்கவும்</span></span>
<span class="line"><span>-&gt; புதிய app register செய்யவும்</span></span>
<span class="line"><span>-&gt; Name / Supported account types / Web redirect URI நிரப்பவும்</span></span>
<span class="line"><span>-&gt; Register</span></span>
<span class="line"><span>-&gt; Application (client) ID copy செய்யவும்</span></span>
<span class="line"><span>-&gt; Authentication-ல் callback URL சரிபார்க்கவும்</span></span>
<span class="line"><span>-&gt; Certificates &amp; secrets-ல் Client Secret உருவாக்கவும்</span></span>
<span class="line"><span>-&gt; API permissions சேர்க்கவும்</span></span>
<span class="line"><span>-&gt; ImgBed-ல் Client ID / Client Secret / Tenant ID நிரப்பவும்</span></span>
<span class="line"><span>-&gt; Get Token கிளிக் செய்யவும்</span></span>
<span class="line"><span>-&gt; callback page-ல் இருந்து Refresh Token copy செய்யவும்</span></span>
<span class="line"><span>-&gt; ImgBed-ல் paste செய்து save செய்யவும்</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Microsoft Entra app registration: <a href="https://learn.microsoft.com/en-us/entra/identity-platform/quickstart-register-app" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/entra/identity-platform/quickstart-register-app</a></li><li>Microsoft identity platform authorization code flow: <a href="https://learn.microsoft.com/en-us/entra/identity-platform/v2-oauth2-auth-code-flow" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/entra/identity-platform/v2-oauth2-auth-code-flow</a></li><li>Microsoft Graph user authentication: <a href="https://learn.microsoft.com/en-us/graph/auth-v2-user" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/graph/auth-v2-user</a></li></ol>`,40)])])}const k=i(c,[["render",p]]);export{y as __pageData,k as default};
